import React, { useEffect, useState } from "react";

function AdminDashboard() {
  const [dailyUsers, setDailyUsers] = useState(null);
  const [level3Users, setLevel3Users] = useState(null);

  useEffect(() => {
    // Get daily active users
    fetch("http://localhost:5000/api/analytics/daily-logins")
      .then((res) => res.json())
      .then((data) => {
        setDailyUsers(data.dailyActiveUsers);
      });

    // Get users who completed level 3
    fetch("http://localhost:5000/api/analytics/level3-completions")
      .then((res) => res.json())
      .then((data) => {
        setLevel3Users(data.level3Completions);
      });
  }, []);

  return (
    <div style={{ padding: "2rem" }}>
      <h2>📊 Admin Analytics Dashboard</h2>
      <p>✅ Daily Active Users: {dailyUsers ?? "Loading..."}</p>
      <p>🏁 Users Who Completed Level 3: {level3Users ?? "Loading..."}</p>
    </div>
  );
}

export default AdminDashboard;
